from agent import *from models.products import *def process_revlist(data, context, session):    for rev in data.xpath("//div[contains(@class,'flex-spaced-col')]/div/h2/a"):        name = rev.xpath("text()").string()        url = rev.xpath("@href").string()        session.queue(Request(url, use="curl"), process_review, dict(context, name=name, url=url))    next = data.xpath("//a[@class='next page-numbers']//@href").string()    if next:       session.queue(Request(next, use="curl"), process_revlist, context)def process_review(data, context, session):    product = Product()    product.name = context['name'].split("Review")[0].split("review")[0]    product.category = data.xpath("//a[contains(@href,'tag')]//text()").string() or 'Review'    product.url = context['url']    product.ssid = context['url'].split("/")[-2]    review = Review()    review.type = 'pro'    review.title = context['name']    review.url = product.url    review.ssid = product.ssid    review.date = data.xpath("//p[@class='border-b-2 border-lightgrey pb-6x mb-6x']//text()").string()        author_name = data.xpath("//p[@class='mb-2']//text()").string().split("By ")[-1]    review.authors.append(Person(name=author_name, ssid=author_name))        pros = data.xpath("//h4[contains(.,'For')]/following-sibling::ul/li//text()")    for pro in pros:        pro = pro.string()        if pro:            review.add_property(type='pros', value=pro)    cons = data.xpath("//h4[contains(.,'Against')]/following-sibling::ul/li//text()")    for con in cons:        con = con.string()        if con:            review.add_property(type='cons', value=con)    grade = data.xpath("//div[@class='flex flex-row text-6xl mt-3x']/i[@class='fas fa-star text-orange']")    if grade:        if data.xpath("//i[@class='text-orange fas fa-star-half-alt']"):            review.grades.append(Grade(type='overall', value=(len(grade)+0.5), best=5))        else:            review.grades.append(Grade(type='overall', value=len(grade), best=5))        summary = data.xpath("//h2[contains(., 'Snap Verdict')]/following-sibling::p[1][not(script)]//text()").string(multiple=True)    if not summary:        summary = data.xpath("//h4[contains(., 'Our Verdict')]/following-sibling::p//text()").string(multiple=True)    if not summary:        summary = data.xpath("//div[@class='text-base lg:text-lg']//text()").string(multiple=True)    if summary:        review.properties.append(ReviewProperty(type='summary', value=summary))        conclusion = data.xpath("//h5[contains(., 'Verdict')]/following-sibling::div/p//text()").string(multiple=True)     if not conclusion:        conclusion = data.xpath("//h2[contains(., 'Verdict')][not(contains(., 'Snap Verdict'))]/following-sibling::p[not(script)]//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[contains(., 'Verdict')][contains(@id, 'review-section-block')]//text()").string(multiple=True)    if not conclusion:        conclusion = data.xpath("//div[contains(., 'Final Thoughts')][contains(@id, 'review-section-block')]//text()").string(multiple=True)                    if conclusion:        conclusion = conclusion.replace("Verdict", '')        review.properties.append(ReviewProperty(type='conclusion', value=conclusion.split('Jabber Digital Media')[0]))    excerpt = data.xpath("//div[@class='w-9/9 lg:w-6/9 flex-spaced-col post-main-content']//p//text()").string(multiple=True)    if excerpt:        if conclusion:            excerpt = excerpt.replace(conclusion, '')        if summary:            excerpt = excerpt.replace(summary, '')        if excerpt:            review.properties.append(ReviewProperty(type='excerpt', value=excerpt))               product.reviews.append(review)    session.emit(product)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.queue(Request("https://camerajabber.com/reviews/", use="curl"), process_revlist, dict())